CODE_EXAMPLE:
// Before
class Manager extends Employee {
  Manager(String name, String id) {
    this.name = name;
    this.id = id;
  }
}

// After
class Employee {
  Employee(String name, String id) {
    this.name = name;
    this.id = id;
  }
}

class Manager extends Employee {
  Manager(String name, String id) {
    super(name, id);
  }
}

